async emit(event: NovelEvent): Promise<void> {
  const list = this.handlers.get(event.type) ?? [];
  for (const { handler } of list) {
    try {
      await handler(event);
    } catch (err) {
      console.error(`[EventBus] handler error for ${event.type}:`, err);
    }
  }
}

